lean_proof_first:
rcases Nat.mod_two_eq_zero_or_one n with h | h;
· have h2 : 2 ∣ n := by { rw [Nat.dvd_iff_mod_eq_zero, h] };
  exact Nat.dvd_mul_of_dvd_right (Nat.dvd_mul_of_dvd_left h2 (n-1)) (n+1);
· have h2 : 2 ∣ (n-1) := by { rw [Nat.dvd_iff_mod_eq_zero, Nat.sub_eq_of_eq_add (by omega : n-1 = n-1)], sorry };
